// 浮点数转ASCII码处理函数，输出10进制数组
function processFloatToASCII(msg) {
    // 获取输入的浮点数
    let inputNumber = msg.payload;

    if (typeof inputNumber !== 'number') {
        // 尝试转换为数字
        inputNumber = parseFloat(inputNumber);
        if (isNaN(inputNumber)) {
            msg.error = "输入必须是一个有效的数字";
            return msg;
        }
    }

    // 四舍五入保留一位小数
    let roundedNumber = Math.round(inputNumber * 10) / 10;

    // 转换为字符串
    let numberString = roundedNumber.toFixed(1);

    // 如果字符串长度超过6位，需要进行处理
    if (numberString.length > 6) {
        // 先尝试分析数字的结构
        const parts = numberString.split('.');
        const intPart = parts[0];
        const decPart = parts[1];

        // 如果整数部分已经大于等于6位，不保留小数位，并四舍五入
        if (intPart.length >= 6) {
            // 计算保留的位数（保留最高几位）
            const digitsToKeep = 6;
            // 计算舍弃位数的十进制位数
            const magnitudeToDrop = Math.pow(10, intPart.length - digitsToKeep);
            // 进行四舍五入
            const newNumber = Math.round(roundedNumber / magnitudeToDrop) * magnitudeToDrop;
            // 转换为字符串（不含小数点）
            numberString = newNumber.toString().substring(0, 6);
        } else {
            // 如果整数部分小于6位，保留小数点并在整数和小数之间分配剩余位数
            // 截取前6位
            numberString = numberString.substring(0, 6);
        }
    }

    // 存储ASCII码结果数组（十进制值）
    let asciiDecimalArray = [];

    // 遍历字符串中的每个字符，转换为ASCII码值（十进制）
    for (let i = 0; i < numberString.length; i++) {
        let charCode = numberString.charCodeAt(i);
        asciiDecimalArray.push(charCode);
    }

    // 创建一个固定长度为6的新数组
    let resultArray = new Array(6).fill(48); // 0x30 是数字0的ASCII码（十进制为48）

    // 从末位开始填充，将原始ASCII码值填入新数组
    // 例如：如果 asciiDecimalArray 长度为4，则填充到 resultArray 的后4位
    const offset = 6 - asciiDecimalArray.length;
    for (let i = 0; i < asciiDecimalArray.length; i++) {
        resultArray[offset + i] = asciiDecimalArray[i];
    }

    // 设置输出为ASCII码数组（十进制）
    msg.payload = resultArray;
    //flow.set("Led_weight")
    // 保存额外的调试信息
    msg.debug = {
        originalNumber: inputNumber,
        roundedNumber: roundedNumber,
        processedString: numberString
    };

    // 添加格式化的输出（用于调试）
    msg.formatted = resultArray.map((val, idx) => 
        `第${idx+1}位ASCII码值：\t${val}`
    ).join('\n');

    return msg;
}

// 执行函数
return processFloatToASCII(msg);

