// 数据解析函数
function parseTagData(msg) {
    // 确保存在响应缓冲区
    if (!msg.responseBuffer || !msg.responseBuffer.buffer) {
        node.error("缺少响应缓冲区数据");
        return null;
    }

    const buffer = msg.responseBuffer.buffer;

    // 检查缓冲区长度是否足够
    if (buffer.length < 20) {
        node.error("响应缓冲区数据不完整，长度应为20字节");
        return null;
    }

    // 解析 HDX 数据
    const hdxTimeoutRaw = buffer[0];
    const hdxTimeout = (hdxTimeoutRaw * 0.02).toFixed(2); // 转换为秒，保留两位小数
    const hdxSignalStrength = buffer[1];
    const hdxCountryCode = ((buffer[2] & 0x0F) << 8) | buffer[3];

    // 解析 HDX 标签卡号 (5字节) - 直接从二进制数据构建
    const hdxTagBytes = [
        buffer[4].toString(16).padStart(2, '0'),
        buffer[5].toString(16).padStart(2, '0'),
        buffer[6].toString(16).padStart(2, '0'),
        buffer[7].toString(16).padStart(2, '0'),
        buffer[8].toString(16).padStart(2, '0')
    ];
    const hdxTagId = parseInt(hdxTagBytes.join(''), 16);

    // 解析 FDX 数据
    const fdxTimeoutRaw = buffer[10];
    const fdxTimeout = (fdxTimeoutRaw * 0.02).toFixed(2); // 转换为秒，保留两位小数
    const fdxSignalStrength = buffer[11];
    const fdxCountryCode = ((buffer[12] & 0x0F) << 8) | buffer[13];

    // 解析 FDX 标签卡号 (5字节)
    const fdxTagBytes = [
        buffer[14].toString(16).padStart(2, '0'),
        buffer[15].toString(16).padStart(2, '0'),
        buffer[16].toString(16).padStart(2, '0'),
        buffer[17].toString(16).padStart(2, '0'),
        buffer[18].toString(16).padStart(2, '0')
    ];
    const fdxTagId = parseInt(fdxTagBytes.join(''), 16);

    // 判断当前标签类型
    let currentTagType = null;
    let output = {};

    // 格式化标签卡号和国家代号的组合
    function formatTagInfo(countryCode, tagId) {
        const formattedCountryCode = countryCode.toString().padStart(3, '0'); // 国家代码保留3位
        const formattedTagId = tagId.toString().padStart(12, '0'); // 标签卡号补充为12位
        return formattedCountryCode + formattedTagId;
    }

    if (hdxTimeoutRaw < 0xFF) {
        currentTagType = "HDX";
        output = {
            timeout: hdxTimeout,
            signalStrength: hdxSignalStrength,
            countryCode: hdxCountryCode,
            tagId: formatTagInfo(hdxCountryCode, hdxTagId), // 格式化后的标签信息
            tagType: currentTagType,
            // 调试信息
            rawTagBytes: hdxTagBytes.join(' ')
        };
    } else if (fdxTimeoutRaw < 0xFF) {
        currentTagType = "FDX";
        output = {
            timeout: fdxTimeout,
            signalStrength: fdxSignalStrength,
            countryCode: fdxCountryCode,
            tagId: formatTagInfo(fdxCountryCode, fdxTagId), // 格式化后的标签信息
            tagType: currentTagType,
            // 调试信息
            rawTagBytes: fdxTagBytes.join(' ')
        };
    } else {
        // 两种标签都超时
        currentTagType = "无有效标签";
        output = {
            tagType: currentTagType
        };
    }

    return output;
}

