function extractCattleNumbers(data) {
    // 如果是简单数组且第一个元素是字符串，可能是列名在第一行
    if (Array.isArray(data) && data.length > 0) {
        // 情况1: 数据格式是二维数组 [["牛只编号", ...], ["CN001", ...], ...]
        if (Array.isArray(data[0])) {
            // 找到表头中牛只编号所在的列索引
            const headerRow = data[0];
            let cattleNumIndex = -1;

            for (let i = 0; i < headerRow.length; i++) {
                const header = String(headerRow[i]).trim();
                if (header === '牛只编号' || header === 'cattle_num' || header === '编号') {
                    cattleNumIndex = i;
                    break;
                }
            }

            // 如果找到了牛只编号列，提取数据
            if (cattleNumIndex >= 0) {
                return data.slice(1) // 跳过表头
                    .map(row => row[cattleNumIndex])
                    .filter(num => num && String(num).trim() !== '');
            }
        }
        // 情况2: 数据是对象数组 [{"牛只编号": "CN001"}, ...]
        else if (typeof data[0] === 'object' && !Array.isArray(data[0])) {
            const keys = Object.keys(data[0]);

            // 找到合适的字段名
            const validColumns = keys.filter(key => 
                key === 'cattle_num' || key === '牛只编号' || key === '编号'
            );

            if (validColumns.length > 0) {
                const column = validColumns[0];
                return data.map(row => row[column])
                    .filter(num => num && String(num).trim() !== '');
            }
        }
        // 情况3: 直接使用数组中的非空值作为牛只编号
        else {
            // 检查第一个元素是否为表头
            const possibleHeader = String(data[0]).trim();
            const startIndex = (possibleHeader === '牛只编号' || possibleHeader === 'cattle_num' || possibleHeader === '编号') ? 1 : 0;

            return data.slice(startIndex)
                .map(item => String(item).trim())
                .filter(num => num !== '');
        }
    }

    return [];
}

