        return null;
    }

    // 统计Result元素出现的频率
    const resultFrequency = {};
    msg.result.forEach(item => {
        if (item && item.Result) {
            const result = item.Result;
            resultFrequency[result] = (resultFrequency[result] || 0) + 1;
        }
    });

    // 根据频率排序Result
    const sortedResults = Object.keys(resultFrequency).sort((a, b) => {
        return resultFrequency[b] - resultFrequency[a];
    });

    // 创建数据库牛号的映射，便于查找
    const dbCattleNumMap = {};
    msg.DB.forEach(item => {
        if (item && item.cattle_num) {
            const id = item.ID;
            const cattleNum = item.cattle_num;
            dbCattleNumMap[cattleNum] = id;
        }
    });

    // 生成对比结果
    const comparisonResults = [];

    // 按频率排序的Result与DB中的cattle_num进行对比
    sortedResults.forEach(result => {
        const frequency = resultFrequency[result];

        // 检查该Result是否存在于DB中的cattle_num
        const matchFound = Object.values(msg.DB).some(item => item.cattle_num === result);

        // 找到匹配的DB ID
        let matchedDbId = null;
        if (matchFound) {
            const matchedItem = msg.DB.find(item => item.cattle_num === result);
            if (matchedItem) {
                matchedDbId = matchedItem.ID;
            }
        }

        // 收集该Result出现的所有记录
        const resultRecords = msg.result.filter(item => item.Result === result);

        // 提取所有匹配记录的准确度
        const accuracies = resultRecords.map(item => item.Accuracy).filter(acc => acc !== undefined && acc !== null);

        // 计算平均准确度
        const avgAccuracy = accuracies.length > 0 ?
            accuracies.reduce((sum, acc) => sum + acc, 0) / accuracies.length : null;

        comparisonResults.push({
            result: result,
            frequency: frequency,
            matchInDB: matchFound,
            dbId: matchedDbId,
            resultRecords: resultRecords,
            accuracies: accuracies,
            avgAccuracy: avgAccuracy
        });
    });

    // 创建对比对象，包含原始数据和频率统计
    const comparisonObject = {
        dbData: msg.DB,
        resultData: msg.result,
        resultFrequency: resultFrequency,
        sortedResults: sortedResults.map(result => ({
            result: result,
            frequency: resultFrequency[result]
        }))
    };

    // 创建两个输出消息
    const msg1 = { payload: comparisonObject, comparisonObject: comparisonObject };
    const msg2 = { payload: comparisonResults, comparisonResults: comparisonResults };
    global.set("M18",0)
    return [msg1, msg2];
}

