// 检查数据有效性
if (!originalData || !Array.isArray(originalData)) {
    node.error('没有有效的数据可供插入');
    node.status({fill:"red",shape:"ring",text:"数据无效"});
    return null;
}

// 提取cattle_vidnum字段并过滤空值
const cattleNumbers = originalData
    .map(item => item.cattle_vidnum)
    .filter(num => num !== null && num !== undefined && num !== '');

// 检查是否有有效数据
if (cattleNumbers.length === 0) {
    node.warn('没有找到有效的cattle_vidnum字段');
    node.status({fill:"yellow",shape:"ring",text:"无有效数据"});
    msg.payload = {
        success: true,
        message: '数据库已清空，但没有新数据插入',
        insertedCount: 0
    };
    return msg;
}

// 方法1：使用多VALUES的单个INSERT语句（推荐，最快）
if (cattleNumbers.length <= 500) {  // SQLite一次最多处理约500个VALUES
    // 构建单个INSERT语句插入多条记录
    const values = cattleNumbers.map(num => {
        // 对特殊字符进行转义
        const escapedNum = num.replace(/'/g, "''");
        return `('${escapedNum}')`;
    }).join(',');

    msg.topic = `INSERT INTO cattle_numDB (cattle_num) VALUES ${values}`;
    msg.payload = [];

    // 保存信息供后续使用
    msg.insertInfo = {
        totalCount: cattleNumbers.length,
        cattleNumbers: cattleNumbers,
        method: 'single_insert'
    };

    // 更新状态
    node.status({
        fill:"blue",
        shape:"dot",
        text:`批量插入 ${cattleNumbers.length} 条记录...`
    });

    return msg;

} else {
    // 方法2：数据量太大，需要分批处理
    const batchSize = 500;
    const batches = [];

    for (let i = 0; i < cattleNumbers.length; i += batchSize) {
        const batch = cattleNumbers.slice(i, i + batchSize);
        batches.push(batch);
    }

    // 保存批次信息
    flow.set('batches', batches);
    flow.set('currentBatch', 0);
    flow.set('totalBatches', batches.length);
    flow.set('totalInserted', 0);

    // 处理第一批
    const firstBatch = batches[0];
    const values = firstBatch.map(num => {
        const escapedNum = num.replace(/'/g, "''");
        return `('${escapedNum}')`;
    }).join(',');

    msg.topic = `INSERT INTO cattle_numDB (cattle_num) VALUES ${values}`;
    msg.payload = [];
    msg.insertInfo = {
        currentBatch: 1,
        totalBatches: batches.length,
        batchSize: firstBatch.length,
        method: 'batch_insert'
    };

    node.status({
        fill:"blue",
        shape:"dot",
        text:`插入批次 1/${batches.length}`
    });

    return msg;
}

// 检查是否有错误
if (msg.error) {
    node.error(`插入失败: ${msg.error}`);
    node.status({fill:"red",shape:"ring",text:"插入失败"});

    // 清理流程变量
    flow.set('originalData', null);
    flow.set('batches', null);
    flow.set('currentBatch', null);
    flow.set('totalBatches', null);
    flow.set('totalInserted', null);

    msg.payload = {
        success: false,
        message: '批量插入失败',
        error: msg.error
    };
    return [null, msg];
}

// 检查是否是分批处理
if (msg.insertInfo && msg.insertInfo.method === 'batch_insert') {
    // 分批处理逻辑
    let batches = flow.get('batches');
    let currentBatch = flow.get('currentBatch') || 0;
    let totalBatches = flow.get('totalBatches');
    let totalInserted = flow.get('totalInserted') || 0;

    totalInserted += msg.insertInfo.batchSize;
    flow.set('totalInserted', totalInserted);

    currentBatch++;
    flow.set('currentBatch', currentBatch);

    // 检查是否还有更多批次
    if (currentBatch < totalBatches) {
        // 准备下一批
        const nextBatch = batches[currentBatch];
        const values = nextBatch.map(num => {
            const escapedNum = num.replace(/'/g, "''");
            return `('${escapedNum}')`;
        }).join(',');

        msg.topic = `INSERT INTO cattle_numDB (cattle_num) VALUES ${values}`;
        msg.payload = [];
        msg.insertInfo = {
            currentBatch: currentBatch + 1,
            totalBatches: totalBatches,
            batchSize: nextBatch.length,
            method: 'batch_insert'
        };

        node.status({
            fill:"blue",
            shape:"dot",
            text:`插入批次 ${currentBatch + 1}/${totalBatches}`
        });

        return [msg, null];
    } else {
        // 所有批次完成
        node.status({
            fill:"green",
            shape:"dot",
            text:`成功插入 ${totalInserted} 条记录`
        });

        // 清理流程变量
        flow.set('originalData', null);
        flow.set('batches', null);
        flow.set('currentBatch', null);
        flow.set('totalBatches', null);
        flow.set('totalInserted', null);

        msg.payload = {
            success: true,
            message: '批量插入完成',
            insertedCount: totalInserted,
            totalBatches: totalBatches
        };

        node.warn(`批量插入成功: ${totalInserted} 条记录，分 ${totalBatches} 批完成`);
        return [null, msg];
    }
} else {
    // 单次插入完成（数据量少于500条）
    const count = msg.insertInfo ? msg.insertInfo.totalCount : 0;

    node.status({
        fill:"green",
        shape:"dot",
        text:`成功插入 ${count} 条记录`
    });

    // 清理流程变量
    flow.set('originalData', null);

    msg.payload = {
