            const nameBase = fileNameParts.join('.') || 'image';
            const uniqueFileName = `${nameBase}_${timestamp}.${extension}`;

            // 完整保存路径
            const filePath = path.join(dailyDir, uniqueFileName);

            try {
                // 解码Base64并写入文件
                const imageBuffer = Buffer.from(base64Content, 'base64');
                fs.writeFileSync(filePath, imageBuffer);

                fileInfo = {
                    originalName: fileName,
                    savedName: uniqueFileName,
                    savedPath: filePath,
                    contentType: contentType,
                    size: imageBuffer.length,
                    timestamp: timestamp
                };

                savedFiles.push(fileInfo);
                logInfo(`成功保存图片: ${filePath} (${imageBuffer.length} 字节)`);
            } catch (fileErr) {
                logInfo(`保存图片失败: ${fileErr.message}`);
                fileInfo = {
                    error: `文件写入失败: ${fileErr.message}`,
                    attempted: uniqueFileName
                };
            }
        } else {
            logInfo("请求中不包含图片数据");
        }
    } else {
        // 尝试解析字符串格式的请求体
        try {
            const parsedBody = JSON.parse(msg.req.body);
            jsonData = parsedBody.jsonData || parsedBody;
            logInfo("成功解析字符串格式的JSON数据");
        } catch (parseErr) {
            logInfo(`无法解析请求体: ${parseErr.message}`);
            jsonData = { error: "请求体格式不正确" };
        }
    }
} catch (err) {
    logInfo(`处理数据时出错: ${err.message}`);
    jsonData = { error: `处理请求时出错: ${err.message}` };
}

// 准备响应数据
msg.payload = {
    status: fileInfo && fileInfo.error ? "partial-success" : "success",
    message: fileInfo && fileInfo.error ? "成功接收JSON数据，但图片处理失败" : "数据接收成功",
    receivedAt: new Date().toISOString(),
    receivedData: jsonData,
    savedFiles: savedFiles,
    storageDir: dailyDir
};

// 添加文件路径信息便于后续处理
if (fileInfo && !fileInfo.error) {
    msg.filePath = fileInfo.savedPath;
    msg.fileName = fileInfo.savedName;
}

return msg;

