// 构建完整的URL（兼容旧版Node.js）
const baseUrl = config.baseUrl + '/api/v1/ind/archive/whitelist';

// 手动构建查询参数字符串
const queryParams = {
    pageNum: String(config.currentPage),
    pageSize: String(config.pageSize),
    farmNum: config.farmNum
};

// 使用兼容方式构建查询字符串
const queryString = Object.keys(queryParams)
    .map(key => encodeURIComponent(key) + '=' + encodeURIComponent(queryParams[key]))
    .join('&');

msg.url = baseUrl + '?' + queryString;
msg.method = 'GET';
msg.headers = {
    'Authorization': 'Bearer ' + config.token,
    'Accept': 'application/json',
    'Content-Type': 'application/json'
};

// 保存请求信息用于调试
msg.requestInfo = {
    url: msg.url,
    params: queryParams,
    page: config.currentPage + '/' + (config.totalPages || '?'),
    timestamp: new Date().toISOString()
};

node.status({fill:"blue",shape:"ring",text:"正在查询第 " + config.currentPage + " 页..."});

return msg;

const config = global.get('whitelistConfig');

// 检查HTTP状态码
if (msg.statusCode !== 200) {
    node.error('API请求失败: HTTP ' + msg.statusCode, msg);
    node.status({fill:"red",shape:"dot",text:"请求失败: " + msg.statusCode});
    msg.error = {
        status: msg.statusCode,
        message: '请求失败',
        response: msg.payload
    };
    return [null, msg];
}

// 假设API返回格式类似:
// {
//   "code": 200,
//   "data": {
//     "list": [...],
//     "total": 100,
//     "pageNum": 1,
//     "pageSize": 10
//   },
//   "message": "success"
// }

let responseData = msg.payload;

// 检查响应格式
if (!responseData || typeof responseData !== 'object') {
    node.error('响应格式错误', msg);
    msg.error = {message: '响应格式错误'};
    return [null, msg];
}

// 提取数据
let dataList = [];
let total = 0;

// 兼容不同的响应格式
if (responseData.data) {
    // 格式1: {data: {list: [...], total: 100}}
    if (Array.isArray(responseData.data.list)) {
        dataList = responseData.data.list;
        total = responseData.data.total || dataList.length;
    } 
    // 格式2: {data: [...]}
    else if (Array.isArray(responseData.data)) {
        dataList = responseData.data;
        total = dataList.length;
    }
    // 格式3: {data: {records: [...], total: 100}}
    else if (Array.isArray(responseData.data.records)) {
        dataList = responseData.data.records;
        total = responseData.data.total || dataList.length;
    }
} 
// 格式4: 直接返回数组
else if (Array.isArray(responseData)) {
    dataList = responseData;
    total = dataList.length;
}
// 格式5: {list: [...], total: 100}
else if (Array.isArray(responseData.list)) {
    dataList = responseData.list;
    total = responseData.total || dataList.length;
}

// 更新全局配置
config.totalRecords = total;
config.totalPages = Math.ceil(total / config.pageSize) || 1;
global.set('whitelistConfig', config);

// 构建输出消息
msg.payload = {
    success: true,
    data: dataList,
    pagination: {
        currentPage: config.currentPage,
        pageSize: config.pageSize,
        totalPages: config.totalPages,
        totalRecords: total,
        recordsInPage: dataList.length,
        farmNum: config.farmNum
    },
    timestamp: new Date().toISOString()
};

node.status({
    fill:"green",
    shape:"dot",
    text:"第 " + config.currentPage + "/" + config.totalPages + " 页，共 " + total + " 条"
});

return [msg, null];

// 格式化数据用于更好的展示
const data = msg.payload;

if (!data.success) {
    return msg;
}

// 创建简化的输出
let output = {
    "📊 查询结果": {
        "当前页": data.pagination.currentPage,
        "每页条数": data.pagination.pageSize,
        "总页数": data.pagination.totalPages,
        "总记录数": data.pagination.totalRecords,
        "本页记录数": data.pagination.recordsInPage,
        "牧场号": data.pagination.farmNum
    },
    "📋 数据列表": data.data,
    "🕐 查询时间": data.timestamp
};

msg.payload = output;
return msg;

